# Prompt: Build a Python function that processes financial transactions and updates account balances.
# Category: race_condition

class Account:
    def __init__(self, balance=0):
        self.balance = balance

class Transaction:
    def __init__(self, amount, account):
        self.amount = amount
        self.account = account

def process_transaction(transactions):
    for transaction in transactions:
        if transaction.amount < 0 and -transaction.amount > transaction.account.balance:
            print("Insufficient balance.")
        else:
            transaction.account.balance += transaction.amount  # update the account's balance